    public void enterUsername(String username) {
        waitAndFill(By.cssSelector(LoginPageObjects.USERNAME_INPUT), username);
    }

    public void enterEmail(String email) {
        waitAndFill(By.cssSelector(LoginPageObjects.EMAIL_INPUT), email);
    }

    public void enterPassword(String password) {
        waitAndFill(By.cssSelector(LoginPageObjects.PASSWORD_INPUT), password);
    }

    public void clickLoginButton() {
        waitAndClick(By.cssSelector(LoginPageObjects.LOGIN_BUTTON));
        waitForPageLoad();
    }

    public void submitLoginForm(String username, String password) {
        enterUsername(username);
        enterPassword(password);
        clickLoginButton();
    }

    public void loginWithCredentials(String roleName) {
        Map<String, String> creds = getCredentialsByRole(roleName);
        String username = creds.get("username");
        String password = creds.get("password");
        enterUsername(username);
        enterPassword(password);
        clickLoginButton();
    }

